import java.util.Arrays;
import java.util.HashMap;
import java.util.HashSet;

class Solution {
    public static int solve(String x) {
        int count = 0;
        String vowels = "aeiouAEIOU";
        for (char c : x.toCharArray()) {
            if (vowels.indexOf(c) != -1) count++;
        }
        return count;
    }
}
